// ── Cadence gate ───────────────────────────────────────────────────────────
// Why this node exists.
//
// The Schedule Trigger's "every 2 days" option is NOT a calendar rule. n8n
// compiles it to a cron that fires EVERY day at 18:00 and then gates it with
// recurrenceCheck(), which stamps "last fired = today" the moment the trigger
// emits — before a single downstream node has run. So when a run died later
// (Gemini 5xx, a GitHub blip, a Sheets hiccup) the slot was already spent and
// the next attempt was a full 2 days away. That is what produced the 4-day and
// 6-day gaps in the blog: one lost run cost four days, two cost six.
//
// The trigger now fires daily and the cadence is decided here, from the sheet
// itself — the real record of when we last published. A run that fails is
// simply retried tomorrow instead of being lost for two days.

const MIN_DAYS_BETWEEN_POSTS = 2;

const items = $input.all();
if (items.length === 0) {
  throw new Error(
    'No rows received from Google Sheets. Check the sheet ID, tab name, and credential permissions.',
  );
}

// Normalise a "Date Used" cell to yyyy-MM-dd. Accepts the ISO value this
// workflow writes, plus the formats Google Sheets may reformat it into.
function toIsoDate(value) {
  const s = String(value == null ? '' : value).trim();
  if (!s) return null;

  const iso = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (iso) return iso[1] + '-' + iso[2] + '-' + iso[3];

  const slash = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/); // M/D/YYYY
  if (slash) {
    const pad = (n) => String(n).padStart(2, '0');
    return slash[3] + '-' + pad(slash[1]) + '-' + pad(slash[2]);
  }

  const parsed = new Date(s);
  if (!isNaN(parsed.getTime())) return parsed.toISOString().slice(0, 10);

  return null;
}

let usedCount = 0;
let lastUsed = null;

for (const item of items) {
  const row = item.json;
  const keys = Object.keys(row).filter((k) => k !== 'row_number');
  const statusKey = keys[1];
  const dateKey = keys.length > 2 ? keys[2] : null;
  if (!statusKey) continue;

  const status = String(row[statusKey] == null ? '' : row[statusKey]).toLowerCase().trim();
  if (status !== 'used') continue;
  usedCount++;

  const iso = dateKey ? toIsoDate(row[dateKey]) : null;
  if (iso && (!lastUsed || iso > lastUsed)) lastUsed = iso;
}

// Genuine first run — nothing published yet, so go ahead.
if (usedCount === 0) return items;

// Rows are marked used but not one date is readable. Fail loudly instead of
// publishing every single day and burning the whole topic queue.
if (!lastUsed) {
  throw new Error(
    usedCount + ' row(s) are marked "used" but none has a readable "Date Used" value. ' +
    'Expected yyyy-MM-dd (e.g. 2026-07-18). Fix column C before the schedule can resume.',
  );
}

const today = $now.toFormat('yyyy-MM-dd');
const toUtc = (s) =>
  Date.UTC(Number(s.slice(0, 4)), Number(s.slice(5, 7)) - 1, Number(s.slice(8, 10)));
const daysSince = Math.round((toUtc(today) - toUtc(lastUsed)) / 86400000);

// Not due yet: return no items. Every downstream node is skipped and the
// execution ends cleanly — no error, no alert, nothing marked used.
if (daysSince < MIN_DAYS_BETWEEN_POSTS) return [];

// Due. Pass the rows through untouched — "Find First Pending Topic" reads the
// sheet's own column order, so no extra keys may be added here.
return items;

const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No data received from Google Sheets. Check the sheet ID, tab name, and permissions.');
}
for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const keys = Object.keys(row).filter(k => k !== 'row_number');
  const colA = keys[0];
  const colB = keys[1];
  const colC = keys.length > 2 ? keys[2] : null;
  if (colB && row[colB] && row[colB].toString().toLowerCase().trim() === 'pending' && row[colA] && row[colA].toString().trim()) {
    const topic = row[colA].toString().trim();
    return [{ json: { topic, rowNumber: row.row_number || (i + 2), colA, colB, colC } }];
  }
}
throw new Error('No pending topics found in the Wady Topics sheet (column B must contain "pending").');

const raw = $input.first().json.text;
if (!raw) throw new Error('No content received from Gemini (English).');
let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/, '').trim();
}

// The model sometimes mangles the body marker (writes "---BODY", glues it to the
// first heading, or drops it entirely). Split robustly with layered fallbacks.
function splitHeaderBody(text) {
  const m = text.match(/[-=]{2,}\s*BODY(?:\s*[-=]{2,})?/i);
  if (m) { const i = text.indexOf(m[0]); return [text.slice(0, i), text.slice(i + m[0].length)]; }
  const rt = text.match(/^READTIME:.*$/mi);
  if (rt) { const i = text.indexOf(rt[0]) + rt[0].length; return [text.slice(0, i), text.slice(i)]; }
  const h = text.match(/^##\s.*$/m);
  if (h) { const i = text.indexOf(h[0]); return [text.slice(0, i), text.slice(i)]; }
  return [text, ''];
}

const [header, bodyRaw] = splitHeaderBody(clean);
let body = bodyRaw.trim()
  .replace(/^[-=]{2,}\s*BODY\s*[-=]{0,}\s*/i, '')
  .replace(/^[-=]{3,}\s*/, '')
  .trim();
if (!body) throw new Error('English body is empty after parsing the model output.');

function field(name) {
  const m = header.match(new RegExp('^' + name + ':\\s*(.+)$', 'mi'));
  return m ? m[1].trim() : '';
}

const validServices = ['website-design','search-engine-optimization','content-production','social-media-management','mobile-app-design','brand-identity','ecommerce-design','digital-marketing'];
let service = field('SERVICE').toLowerCase().replace(/[^a-z-]/g, '');
if (!validServices.includes(service)) service = 'content-production';

let readMin = parseInt(field('READTIME'), 10);
if (!readMin || readMin < 1) readMin = 8;

// EXCERPT can be skipped by the model — fall back to DESCRIPTION, then first body sentence.
let enExcerpt = field('EXCERPT');
if (!enExcerpt) {
  const firstPara = body.split(/\n\s*\n/).map(s => s.replace(/^#+\s.*$/gm, '').trim()).find(s => s.length > 0) || '';
  enExcerpt = (field('DESCRIPTION') || firstPara.split(/(?<=[.!?])\s/)[0] || '').slice(0, 180);
}

const ctx = $('Find First Pending Topic').first().json;
return [{ json: {
  topic: ctx.topic,
  rowNumber: ctx.rowNumber,
  colA: ctx.colA,
  colB: ctx.colB,
  colC: ctx.colC,
  service,
  enTitle: field('TITLE') || ctx.topic,
  enExcerpt,
  enDescription: field('DESCRIPTION') || enExcerpt,
  enReadMin: readMin,
  enBody: body,
} }];

const raw = $input.first().json.text;
if (!raw) throw new Error('No content received from Gemini (Arabic).');
let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/, '').trim();
}

// Same robust split as the English node — tolerate a mangled or missing marker.
function splitHeaderBody(text) {
  const m = text.match(/[-=]{2,}\s*BODY(?:\s*[-=]{2,})?/i);
  if (m) { const i = text.indexOf(m[0]); return [text.slice(0, i), text.slice(i + m[0].length)]; }
  const rt = text.match(/^READTIME:.*$/mi);
  if (rt) { const i = text.indexOf(rt[0]) + rt[0].length; return [text.slice(0, i), text.slice(i)]; }
  const h = text.match(/^##\s.*$/m);
  if (h) { const i = text.indexOf(h[0]); return [text.slice(0, i), text.slice(i)]; }
  return [text, ''];
}

const [header, bodyRaw] = splitHeaderBody(clean);
let body = bodyRaw.trim()
  .replace(/^[-=]{2,}\s*BODY\s*[-=]{0,}\s*/i, '')
  .replace(/^[-=]{3,}\s*/, '')
  .trim();
if (!body) throw new Error('Arabic body is empty after parsing the model output.');

function field(name) {
  const m = header.match(new RegExp('^' + name + ':\\s*(.+)$', 'mi'));
  return m ? m[1].trim() : '';
}

const en = $('Clean English Output').first().json;
let readMin = parseInt(field('READTIME'), 10);
if (!readMin || readMin < 1) readMin = en.enReadMin;

let arExcerpt = field('EXCERPT');
if (!arExcerpt) {
  const firstPara = body.split(/\n\s*\n/).map(s => s.replace(/^#+\s.*$/gm, '').trim()).find(s => s.length > 0) || '';
  arExcerpt = (field('DESCRIPTION') || firstPara).slice(0, 180);
}

return [{ json: {
  ...en,
  arTitle: field('TITLE') || en.enTitle,
  arExcerpt,
  arDescription: field('DESCRIPTION') || arExcerpt,
  arReadMin: readMin,
  arBody: body,
} }];

const d = $input.first().json;

// Map the AI-chosen service to its blog number + bilingual kicker (matches existing posts in the repo)
const SERVICES = {
  'website-design':             { num: 1, kicker: 'Design',            kickerAr: 'تصميم' },
  'search-engine-optimization': { num: 2, kicker: 'SEO',               kickerAr: 'سيو' },
  'content-production':         { num: 3, kicker: 'Content',           kickerAr: 'محتوى' },
  'social-media-management':    { num: 4, kicker: 'Social media',      kickerAr: 'سوشيال ميديا' },
  'mobile-app-design':          { num: 5, kicker: 'Mobile apps',       kickerAr: 'تطبيقات' },
  'brand-identity':             { num: 6, kicker: 'Brand identity',    kickerAr: 'هوية تجارية' },
  'ecommerce-design':           { num: 7, kicker: 'E-commerce',        kickerAr: 'تجارة إلكترونية' },
  'digital-marketing':          { num: 8, kicker: 'Digital marketing', kickerAr: 'تسويق إلكتروني' },
};
const svc = SERVICES[d.service] || SERVICES['content-production'];

// Dates (code node $now respects the instance timezone, Asia/Riyadh)
const now = $now;
const iso = now.toFormat('yyyy-MM-dd');
const enMonths = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const arMonths = ['كانون الثاني','شباط','آذار','نيسان','أيار','حزيران','تموز','آب','أيلول','تشرين الأول','تشرين الثاني','كانون الأول'];
const y = now.year, mo = now.month, day = now.day;
const enDate = enMonths[mo - 1] + ' ' + day + ', ' + y;
const toAr = (n) => String(n).replace(/[0-9]/g, (ch) => '٠١٢٣٤٥٦٧٨٩'[ch]);
const arDate = toAr(day) + ' ' + arMonths[mo - 1] + ' ' + toAr(y);

const num = String(svc.num).padStart(2, '0');
const numAr = toAr(num);

const enRead = d.enReadMin + ' min';
const arUnit = (d.arReadMin >= 3 && d.arReadMin <= 10) ? 'دقائق' : 'دقيقة';
const arRead = toAr(d.arReadMin) + ' ' + arUnit;

// Wrap every text value in double quotes; the repo frontmatter parser strips one
// surrounding pair, so we replace any inner double quote with a typographic one.
const q = (s) => '"' + String(s == null ? '' : s).replace(/"/g, '’').replace(/\r?\n/g, ' ').trim() + '"';

const fm = [
  '---',
  'title: ' + q(d.enTitle),
  'titleAr: ' + q(d.arTitle),
  'excerpt: ' + q(d.enExcerpt),
  'excerptAr: ' + q(d.arExcerpt),
  'description: ' + q(d.enDescription),
  'descriptionAr: ' + q(d.arDescription),
  'num: ' + num,
  'numAr: ' + numAr,
  'kicker: ' + q(svc.kicker),
  'kickerAr: ' + q(svc.kickerAr),
  'date: ' + q(enDate),
  'dateAr: ' + q(arDate),
  'isoDate: ' + iso,
  'readTime: ' + q(enRead),
  'readTimeAr: ' + q(arRead),
  'serviceNum: ' + num,
  '---',
].join('\n');

// Defensive normalization: enforce the renderer's supported markdown subset
function normalize(md) {
  let t = (md || '').trim();
  t = t.replace(/^(\s*)\*\s+/gm, '$1- ');   // * bullets -> - bullets
  t = t.replace(/^#{3,}\s*/gm, '## ');        // ### or deeper -> ##
  t = t.replace(/\*\*(.+?)\*\*/g, '$1');      // strip **bold**
  return t.trim();
}
const enBody = normalize(d.enBody);
const arBody = normalize(d.arBody);
const fileBody = enBody + '\n\n<!-- AR -->\n\n' + arBody;
const fileContent = fm + '\n\n' + fileBody + '\n';

// Slug from the English title (<= 60 chars, no trailing hyphen)
let slug = (d.enTitle || d.topic).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
if (slug.length > 60) {
  const cut = slug.substring(0, 60);
  const lh = cut.lastIndexOf('-');
  slug = lh > 0 ? cut.substring(0, lh) : cut;
}
slug = slug.replace(/-$/, '') || ('post-' + iso);

return [{ json: {
  topic: d.topic,
  rowNumber: d.rowNumber,
  colA: d.colA,
  colB: d.colB,
  colC: d.colC,
  todayDate: iso,
  service: d.service,
  num,
  slug,
  articleTitle: d.enTitle,
  fileContent,
} }];

const t = $('Assemble Blog File').first().json;
const row = {};
row[t.colA] = t.topic;
row[t.colB] = 'used';
if (t.colC) row[t.colC] = t.todayDate;
return [{ json: row }];

// Flatten the Error Trigger payload into a single row for the log tab.
// Payload shape:
//   { execution: { id, url, error: { message }, lastNodeExecuted, mode },
//     workflow:  { id, name } }

const d = $input.first().json;
const execution = d.execution || {};
const workflow = d.workflow || {};
const error = execution.error || {};

const message = String(error.message || 'Unknown error')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 500);

return [{
  json: {
    'Timestamp': $now.toFormat('yyyy-MM-dd HH:mm:ss'),
    'Workflow': workflow.name || '(unknown)',
    'Failed Node': execution.lastNodeExecuted || '(unknown)',
    'Error': message,
    'Execution URL': execution.url || '',
  },
}];
